public int minTimeToType(String word) {
    int time = 0, position = 0;
    for (char c : word.toCharArray()) {
        int next_position = c - 'a';
        int diff = Math.abs(next_position - position);
        time += Math.min(diff, 26 - diff) + 1;
        position = next_position;
    }
    return time;
}
```

